- Install Redis using `sudo apt-get install redis-server` on Ubuntu.
- Use `npm install express redis` to add Express and Redis packages.
- Configure Redis client in your app:
  ```javascript
  const redis = require('redis');
  const client = redis.createClient();
  ```
- Set cache with TTL (time-to-live):
  ```javascript
  client.setex('key', 60, 'value'); // Cache for 1 minute
  ```
- Retrieve cached data:
  ```javascript
  client.get('key', (err, reply) => {
    if (err) throw err;
    console.log(reply);
  });
  ```
- Invalidate cache:
  ```javascript
  client.del('key');
  ```
- Use Redis middleware for caching routes:
  ```javascript
  const express = require('express');
  const redis = require('redis');
  const app = express();
  const client = redis.createClient();

  app.use((req, res, next) => {
    const key = req.originalUrl;
    client.get(key, (err, reply) => {
      if (err) throw err;
      if (reply) {
        res.send(reply);
      } else {
        res.on('finish', () => {
          client.setex(key, 60, res.body); // Cache response for 1 minute
        });
        next();
      }
    });
  });

  app.get('/data', (req, res) => {
    res.send('Data from server');
  });

  app.listen(3000);
  ```
- Key config options:
  - `host`: Redis server host.
  - `port`: Redis server port.
  - `password`: If Redis is password protected.
